from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

REDIS_URL = os.getenv("REDIS_URL", "redis://localhost:6379/0")
r = redis.Redis.from_url(REDIS_URL, decode_responses=True)

@app.route("/admin/redis", methods=["GET", "POST"])
def admin_redis():
    command = request.args.get("command") or (request.json.get("command") if request.is_json else None)
    if not command:
        return jsonify({"error": "Missing command"}), 400

    args = request.args.getlist("arg")
    json_args = []
    if request.is_json:
        json_args = request.json.get("args", [])
    full_args = json_args if json_args else args

    try:
        result = r.execute_command(command, *full_args)
        return jsonify({"ok": True, "result": result})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", 5000)))